for (i in 0 until parts.length()) {
    val part = parts.getJSONObject(i)
    if (part.has("text")) {
        responseBlocks.put(JSONObject().put("type", "text").put("content", part.getString("text")))
    }
    if (part.has("functionCall")) {
        val call = part.getJSONObject("functionCall")
        val name = call.getString("name")
        val code = call.optJSONObject("args")?.optString("code") ?: ""

        val executionResult = if (code.isNotEmpty()) {
            onStatusUpdate("Executing Python...")
            withContext(Dispatchers.IO) { executor.callAttr("run_code", code).toString() }
        } else "Error: No code provided"

        responseBlocks.put(JSONObject().put("type", "code_execution").put("code", code).put("result", executionResult))

        nextToolResults.put(JSONObject().put("name", name).put("content", executionResult))
        foundFunctionCall = true
    }
}

